import { useCallback } from "react";
import Particles from "@tsparticles/react";
import { loadSlim } from "tsparticles-slim";

export default function LogisticsParticles() {

  const particlesInit = useCallback(async (engine) => {
    await loadSlim(engine);
  }, []);

  const options = {

    fullScreen: {
      enable: true,
      zIndex: -1
    },

    background: {
      color: "transparent"
    },

    fpsLimit: 60,

    particles: {

      number: {
        value: 120,
        density: {
          enable: true,
          area: 800
        }
      },

      color: {
        value: ["#7ddf64", "#c7fab6", "#9ae6b4"]
      },

      shape: {
        type: "circle"
      },

      opacity: {
        value: { min: 0.2, max: 0.7 }
      },

      size: {
        value: { min: 2, max: 7 }
      },

      blur: {
        enable: true,
        value: 3
      },

      links: {
        enable: true,
        distance: 160,
        opacity: 0.25,
        width: 1,
        color: "#a7f3a0"
      },

      move: {

        enable: true,

        speed: 1.2,

        direction: "none",

        random: false,

        straight: false,

        outModes: {
          default: "bounce"
        }

      }

    },

    interactivity: {

      events: {

        onHover: {
          enable: true,
          mode: "repulse"
        },

        onClick: {
          enable: true,
          mode: "push"
        }

      },

      modes: {

        repulse: {
          distance: 120,
          duration: 0.4
        },

        push: {
          quantity: 4
        }

      }

    }

  };

  return <Particles init={particlesInit} options={options} />;
}
